+        let start = Instant::now();
+        self.ensure_built()?;
+
+        // Build escalation trigger
+        let trigger = self.build_trigger();
+
+        // Decide tier
+        let use_exact = trigger.should_escalate(&self.policy);
+
+        if use_exact {
+            self.query_tier2_st(s, t, start)
+        } else {
+            self.query_tier1_st(s, t, start)
