+        let config = LevelConfig::default();
+
+        let level = BmsspJTreeLevel::new(contracted, config).unwrap();
+        assert_eq!(level.level(), 0);
+
+        let stats = level.statistics();
+        assert_eq!(stats.vertex_count, 4);
+        assert_eq!(stats.edge_count, 3);
