+use std::collections::{HashMap, HashSet};
+use std::sync::atomic::{AtomicUsize, Ordering};
+use std::sync::Arc;
+
+// ============================================================================
+// Test Helper Structures (mock implementations for testing)
+// These mirror the structures defined in ADR-002 and addendums
